package com.enterprise.app.user;

import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.Optional;
import java.util.UUID;

@Service
public class UserService {

    private final UserRepository userRepository;

    public UserService(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @Transactional
    public UserEntity createUser(String email, String displayName) {
        if (userRepository.existsByEmailIgnoreCase(email)) {
            throw new IllegalArgumentException("Email already exists");
        }
        UserEntity u = new UserEntity();
        u.setExternalId(UUID.randomUUID().toString());
        u.setEmail(email);
        u.setDisplayName(displayName);
        u.setStatus(UserStatus.ACTIVE);
        return userRepository.save(u);
    }

    @Transactional(readOnly = true)
    public Optional<UserEntity> getByExternalId(String externalId) {
        return userRepository.findByExternalId(externalId);
    }

    @Transactional
    public UserEntity updateStatus(String externalId, UserStatus status) {
        UserEntity user = userRepository.findByExternalId(externalId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        user.setStatus(status);
        return userRepository.save(user);
    }
}

