package com.enterprise.app.txn;

import com.enterprise.app.user.UserEntity;
import com.enterprise.app.user.UserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.util.List;
import java.util.UUID;

@Service
public class TransactionService {

    private final TransactionRepository transactionRepository;
    private final UserRepository userRepository;

    public TransactionService(TransactionRepository transactionRepository, UserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    @Transactional
    public TransactionEntity createTransaction(String userExternalId, BigDecimal amount, String currency) {
        UserEntity user = userRepository.findByExternalId(userExternalId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        TransactionEntity tx = new TransactionEntity();
        tx.setReference(UUID.randomUUID().toString());
        tx.setUser(user);
        tx.setAmount(amount);
        tx.setCurrency(currency);
        tx.setStatus(TransactionStatus.PENDING);
        return transactionRepository.save(tx);
    }

    @Transactional(readOnly = true)
    public List<TransactionEntity> listUserTransactions(String userExternalId) {
        UserEntity user = userRepository.findByExternalId(userExternalId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        return transactionRepository.findByUser_IdOrderByCreatedAtDesc(user.getId());
    }

    @Transactional
    public TransactionEntity updateStatus(String reference, TransactionStatus status) {
        TransactionEntity tx = transactionRepository.findByReference(reference)
                .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        tx.setStatus(status);
        return transactionRepository.save(tx);
    }
}

