package com.enterprise.app.api;

import com.enterprise.app.api.dto.CreateUserRequest;
import com.enterprise.app.user.UserEntity;
import com.enterprise.app.user.UserService;
import com.enterprise.app.user.UserStatus;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserService userService;

    public UserController(UserService userService) {
        this.userService = userService;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public UserEntity create(@Valid @RequestBody CreateUserRequest req) {
        return userService.createUser(req.getEmail(), req.getDisplayName());
    }

    @GetMapping("/{externalId}")
    public UserEntity get(@PathVariable String externalId) {
        return userService.getByExternalId(externalId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
    }

    @PatchMapping("/{externalId}/status")
    public UserEntity updateStatus(@PathVariable String externalId, @RequestParam UserStatus status) {
        return userService.updateStatus(externalId, status);
    }
}

