package com.enterprise.app.api;

import com.enterprise.app.api.dto.CreateTransactionRequest;
import com.enterprise.app.txn.TransactionEntity;
import com.enterprise.app.txn.TransactionService;
import com.enterprise.app.txn.TransactionStatus;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/users/{externalId}/transactions")
public class TransactionController {

    private final TransactionService transactionService;

    public TransactionController(TransactionService transactionService) {
        this.transactionService = transactionService;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public TransactionEntity create(@PathVariable String externalId, @Valid @RequestBody CreateTransactionRequest req) {
        return transactionService.createTransaction(externalId, req.getAmount(), req.getCurrency());
    }

    @GetMapping
    public List<TransactionEntity> list(@PathVariable String externalId) {
        return transactionService.listUserTransactions(externalId);
    }

    @PatchMapping("/{reference}/status")
    public TransactionEntity updateStatus(@PathVariable String reference, @RequestParam TransactionStatus status) {
        return transactionService.updateStatus(reference, status);
    }
}

// src/main/java/com/enterprise/app/api/ApiExceptionHandler.java
package com.enterprise.app.api;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.time.Instant;
import java.util.HashMap;
import java.util.Map;

@RestControllerAdvice
public class ApiExceptionHandler {

    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<Map<String, Object>> handleIllegalArgument(IllegalArgumentException ex) {
        Map<String, Object> body = new HashMap<>();
        body.put("timestamp", Instant.now().toString());
        body.put("error", "Bad Request");
        body.put("message", ex.getMessage());
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(body);
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<Map<String, Object>> handleValidation(MethodArgumentNotValidException ex) {
        Map<String, Object> body = new HashMap<>();
        body.put("timestamp", Instant.now().toString());
        body.put("error", "Validation Failed");
        body.put("message", ex.getBindingResult().getAllErrors().stream().findFirst().map(e -> e.getDefaultMessage()).orElse("Invalid request"));
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(body);
    }
}